using Xunit;
using Moq;

public class PaymentServiceTests
{
    [Fact]
    public async Task CreateCharge_ValidAmount_ReturnsCharge()
    {
        var mockClient = new Mock<IStripeClient>();
        var service = new PaymentService(mockClient.Object);
        var result = await service.CreateCharge(2000, "usd");
        Assert.NotNull(result);
        Assert.Equal(2000, result.Amount);
    }

    [Fact]
    public async Task CreateCharge_NegativeAmount_ThrowsArgumentException()
    {
        var service = new PaymentService(Mock.Of<IStripeClient>());
        await Assert.ThrowsAsync<ArgumentException>(() => service.CreateCharge(-100, "usd"));
    }
}
